namespace sv_2777c3ec91db419484c89e81161959cb.Models;

public class ApplicationData
{
    // Step 1: Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public DateTime LastUpdated { get; set; } = DateTime.UtcNow;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_2777c3ec91db419484c89e81161959cb.Models;

namespace sv_2777c3ec91db419484c89e81161959cb.Services;

/// <summary>
/// Singleton store for wizard data, keyed by session ID.
/// In per-page Interactive Server mode, each navigation creates a new circuit
/// (and new scoped services), so a singleton with session-based keying is needed
/// to persist data across page navigations.
/// </summary>
public class ApplicationDataStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new ApplicationData());
    }

    public void Save(string sessionId, ApplicationData data)
    {
        data.LastUpdated = DateTime.UtcNow;
        _store[sessionId] = data;
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

