arguments.new_str:
﻿@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <div class="wizard-progress">
                    @for (int i = 0; i < Steps.Length; i++)
                    {
                        var step = Steps[i];
                        var stepNumber = i + 1;
                        var css = step.Path == CurrentPath ? "active"
                                : stepNumber < CurrentStep ? "completed"
                                : "";
                        <a href="@step.Path" class="wizard-step @css">
                            <span class="step-number">@stepNumber</span>
                            <span class="step-label">@step.Label</span>
                        </a>
                        @if (stepNumber < Steps.Length)
                        {
                            <span class="step-divider"></span>
                        }
                    }
                </div>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static readonly (string Path, string Label)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    private string CurrentPath => "/" + Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/');
    private int CurrentStep => Array.FindIndex(Steps, s => s.Path == CurrentPath) + 1;
    private bool IsWizardPage => CurrentStep > 0;
}

