@page "/apply/review"
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@using sv_2777c3ec91db419484c89e81161959cb.Models
@using sv_2777c3ec91db419484c89e81161959cb.Services
@inject ApplicationDataStore Store

<PageTitle>Review – Step 4</PageTitle>

<h1>Step 4: Review Your Application</h1>

@if (data is not null)
{
    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            <p><strong>Name:</strong> @data.Name</p>
            <p><strong>Email:</strong> @data.Email</p>
        </div>
    </div>

    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Experience</strong>
            <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (data.JobHistory.Count == 0)
            {
                <p class="text-muted">No job history entered.</p>
            }
            else
            {
                @foreach (var job in data.JobHistory)
                {
                    <div class="mb-2">
                        <strong>@job.Title</strong> at @job.Company (@job.Years)
                    </div>
                }
            }
        </div>
    </div>

    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @if (data.References.Count == 0)
            {
                <p class="text-muted">No references entered.</p>
            }
            else
            {
                @foreach (var r in data.References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> – @r.Email (@r.Relationship)
                    </div>
                }
            }
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3" style="max-width: 600px;">
            Your application has been submitted successfully!
        </div>
    }
}

@code {
    private string? sessionId;
    private ApplicationData? data;
    private bool submitted;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (sessionId is null) return;

        data = Store.GetOrCreate(sessionId);
    }

    private void Back()
    {
        Nav.NavigateTo("/apply/references");
    }

    private void Submit()
    {
        submitted = true;
    }
}

