@page "/apply/experience"
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@using sv_2777c3ec91db419484c89e81161959cb.Models
@using sv_2777c3ec91db419484c89e81161959cb.Services
@inject ApplicationDataStore Store

<PageTitle>Experience – Step 2</PageTitle>

<h1>Step 2: Experience</h1>

@if (jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Click "Add Entry" to get started.</p>
}

@for (int i = 0; i < jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <strong>Entry @(index + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="jobs[index].Company" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <label class="form-label">Title</label>
                <input class="form-control" @bind="jobs[index].Title" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="jobs[index].Years" @bind:event="oninput" />
            </div>
        </div>
    </div>
}

<div class="mb-3">
    <button class="btn btn-outline-secondary" @onclick="AddJob">+ Add Entry</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string? sessionId;
    private List<JobEntry> jobs = [];

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (sessionId is null) return;

        var data = Store.GetOrCreate(sessionId);
        // Deep copy so edits don't mutate the store until Save
        jobs = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();
    }

    private void AddJob() => jobs.Add(new JobEntry());

    private void RemoveJob(int index) => jobs.RemoveAt(index);

    private void SaveData()
    {
        if (sessionId is null) return;
        var data = Store.GetOrCreate(sessionId);
        data.JobHistory = jobs;
        Store.Save(sessionId, data);
    }

    private void Back()
    {
        SaveData();
        Nav.NavigateTo("/apply/personal-info");
    }

    private void Next()
    {
        SaveData();
        Nav.NavigateTo("/apply/references");
    }
}

