@page "/apply/references"
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@using sv_2777c3ec91db419484c89e81161959cb.Models
@using sv_2777c3ec91db419484c89e81161959cb.Services
@inject ApplicationDataStore Store

<PageTitle>References – Step 3</PageTitle>

<h1>Step 3: References</h1>

@if (refs.Count == 0)
{
    <p class="text-muted">No references yet. Click "Add Reference" to get started.</p>
}

@for (int i = 0; i < refs.Count; i++)
{
    var index = i;
    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <strong>Reference @(index + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="refs[index].Name" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="refs[index].Email" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="refs[index].Relationship" @bind:event="oninput" />
            </div>
        </div>
    </div>
}

<div class="mb-3">
    <button class="btn btn-outline-secondary" @onclick="AddRef">+ Add Reference</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string? sessionId;
    private List<ReferenceContact> refs = [];

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (sessionId is null) return;

        var data = Store.GetOrCreate(sessionId);
        refs = data.References.Select(r => new ReferenceContact
        {
            Name = r.Name,
            Email = r.Email,
            Relationship = r.Relationship
        }).ToList();
    }

    private void AddRef() => refs.Add(new ReferenceContact());

    private void RemoveRef(int index) => refs.RemoveAt(index);

    private void SaveData()
    {
        if (sessionId is null) return;
        var data = Store.GetOrCreate(sessionId);
        data.References = refs;
        Store.Save(sessionId, data);
    }

    private void Back()
    {
        SaveData();
        Nav.NavigateTo("/apply/experience");
    }

    private void Next()
    {
        SaveData();
        Nav.NavigateTo("/apply/review");
    }
}

